// Aggregate all metrics for the 24-hour report
const cpuResult  = $('Query CPU 24h').first()?.json?.data?.result?.[0]?.value?.[1];
const memResult  = $('Query Memory 24h').first()?.json?.data?.result?.[0]?.value?.[1];
const alertCount = $('Query Alerts Fired 24h').first()?.json?.data?.result?.length || 0;
const svcResults = $('Query Services Up').first()?.json?.data?.result || [];

// Error log counts per hour
const errorValues = $('Query Error Logs 24h').first()?.json?.data?.result?.[0]?.values || [];
const totalErrors = errorValues.reduce((sum, v) => sum + parseInt(v[1] || '0', 10), 0);
const peakErrors  = Math.max(...errorValues.map(v => parseInt(v[1] || '0', 10)), 0);

// Service availability
const services = svcResults.map(r => ({
  job: r.metric?.job || 'unknown',
  instance: r.metric?.instance || 'unknown',
  availability: (parseFloat(r.value?.[1] || '0') * 100).toFixed(1)
}));
const servicesTable = services.map(s =>
  `  - ${s.job} (${s.instance}): ${s.availability}% uptime`
).join('\n');

const cpuAvg = cpuResult  ? parseFloat(cpuResult).toFixed(1)  + '%' : 'N/A';
const memAvg = memResult  ? parseFloat(memResult).toFixed(1)  + '%' : 'N/A';

const reportDate = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const prompt = `You are an SRE analyst generating a daily infrastructure health report. Summarize the past 24 hours based on the metrics below and provide actionable insights.

## Daily Report — ${reportDate}

### System Metrics (24-hour average)
- Average CPU usage: ${cpuAvg}
- Average Memory usage: ${memAvg}
- Total error log entries: ${totalErrors}
- Peak error logs (per hour): ${peakErrors}
- Alert events fired: ${alertCount}

### Service Availability
${servicesTable || '  - No data available'}

Based on this data, please provide:
1. **Overall health assessment** (1-2 sentences, use: Healthy / Warning / Critical)
2. **Key findings** (3-5 bullet points about notable trends or issues)
3. **Risks identified** (potential problems if current trends continue)
4. **Recommendations** (prioritized action items)
5. **Forecast** (expected behavior in the next 24 hours based on trends)

Keep the report concise, factual, and actionable. Format it clearly.`;

return [{ json: { prompt, cpuAvg, memAvg, totalErrors, peakErrors, alertCount, services, reportDate } }];

const ollamaResponse = $input.first().json;
const ctx = $('Build Report Prompt').first().json;

const aiReport = ollamaResponse?.response || 'AI report generation failed';

const header = `📊 **Daily Infrastructure Report** — ${ctx.reportDate}\n\n` +
  `**Summary:** CPU avg ${ctx.cpuAvg} | Memory avg ${ctx.memAvg} | ` +
  `${ctx.totalErrors} errors | ${ctx.alertCount} alerts fired\n\n---\n\n`;

const text = header + aiReport;

const tags = ['ai-report', 'daily-report', 'infrastructure'];

const now = Date.now();

return [{ json: { text, tags, time: now, timeEnd: now + 3600000 } }];

